const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || input;

function env(name, fallback = '') {
  try {
    if (typeof $env !== 'undefined' && $env[name]) return $env[name];
  } catch (error) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) return process.env[name];
  } catch (error) {}
  return fallback;
}

function headerValue(name) {
  const lower = name.toLowerCase();
  return headers[name] || headers[lower] || headers[name.toUpperCase()] || '';
}

const N8N_API_KEY = env('GDA_QA_N8N_API_KEY');
if (!N8N_API_KEY) throw new Error('GDA_QA_N8N_API_KEY env var not set');
const QA_AGENT_KEY = '';
if (QA_AGENT_KEY && headerValue('x-gda-qa-key') !== QA_AGENT_KEY) {
  return [{ json: { ok: false, statusCode: 403, error: 'Unauthorized QA agent request. Missing or invalid x-gda-qa-key.' } }];
}

const N8N_BASE_URL = env('GDA_QA_N8N_BASE_URL', 'https://n8n.csr-llc.tech').replace(/\/$/, '');
const WEBHOOK_HEADER_NAME = env('GDA_WEBHOOK_AUTH_HEADER_NAME', 'x-gda-key');
const WEBHOOK_HEADER_VALUE = '<REDACTED_WEBHOOK_AUTH>';
const WEBHOOK_BASE_URL = env('GDA_QA_WEBHOOK_BASE_URL', N8N_BASE_URL).replace(/\/$/, '');

const httpRequest = this.helpers.httpRequest.bind(this.helpers);

const reactUsedWebhookTests = [
  { name: 'gda-smoke-test', method: 'GET', path: 'gda-smoke-test' },
  { name: 'gda-platform-health', method: 'POST', path: 'gda-platform-health' },
  { name: 'gda-dashboard-mega', method: 'POST', path: 'gda-dashboard-mega' },
  { name: 'gda-launchpad-funnel', method: 'POST', path: 'gda-launchpad-funnel' },
  { name: 'gda-trends', method: 'POST', path: 'gda-trends' },
  { name: 'gda-opp-tracker', method: 'POST', path: 'gda-opp-tracker' },
  { name: 'gda-daily-actions-list', method: 'POST', path: 'gda-daily-actions-list' },
  { name: 'gda-action-history', method: 'POST', path: 'gda-action-history' },
  { name: 'gda-deep-research-history', method: 'POST', path: 'gda-deep-research-history' },
  { name: 'gda-capture-plan', method: 'POST', path: 'gda-capture-plan' }
];

const retoolUsedWebhookTests = [
  { name: 'gda-platform-health', method: 'POST', path: 'gda-platform-health' },
  { name: 'gda-dashboard-mega', method: 'POST', path: 'gda-dashboard-mega' },
  { name: 'gda-opp-tracker', method: 'POST', path: 'gda-opp-tracker' },
  { name: 'gda-capture-plan', method: 'POST', path: 'gda-capture-plan' }
];

function responseStatus(response) {
  return response.statusCode || response.status || 200;
}

function responseBody(response) {
  return response.body === undefined ? response : response.body;
}

async function n8nApi(path, options = {}) {
  if (!N8N_API_KEY) {
    throw new Error('GDA_QA_N8N_API_KEY is not set.');
  }

  const requestOptions = {
    method: options.method || 'GET',
    url: `${N8N_BASE_URL}${path}`,
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'X-N8N-API-KEY': N8N_API_KEY,
      ...(options.headers || {})
    },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };

  if (options.body !== undefined) {
    requestOptions.body = options.body;
  }

  const response = await httpRequest(requestOptions);
  const status = responseStatus(response);

  return {
    status,
    ok: status >= 200 && status < 300,
    body: responseBody(response)
  };
}

async function fetchAllWorkflows() {
  const workflows = [];
  let cursor = undefined;

  for (let page = 0; page < 20; page += 1) {
    const query = cursor ? `?limit=100&cursor=${encodeURIComponent(cursor)}` : '?limit=100';
    const result = await n8nApi(`/api/v1/workflows${query}`);

    if (!result.ok) {
      throw new Error(`n8n workflow inventory failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
    }

    const data = Array.isArray(result.body) ? result.body : (result.body.data || []);
    workflows.push(...data);

    cursor = result.body.nextCursor;
    if (!cursor) break;
  }

  return workflows;
}

function workflowInventoryItem(workflow) {
  const nodes = workflow.nodes || [];

  const triggerNodes = nodes
    .filter((node) =>
      String(node.type || '').includes('webhook') ||
      String(node.type || '').includes('scheduleTrigger') ||
      String(node.type || '').includes('manualTrigger')
    )
    .map((node) => ({
      name: node.name,
      type: node.type,
      disabled: Boolean(node.disabled),
      webhookPath: node.parameters?.path || node.webhookPath || null,
      httpMethod: node.parameters?.httpMethod || node.parameters?.method || null
    }));

  const likelyWebhookUrls = triggerNodes
    .filter((node) => node.webhookPath)
    .flatMap((node) => [
      `${N8N_BASE_URL}/webhook-test/${node.webhookPath}`,
      `${N8N_BASE_URL}/webhook/${node.webhookPath}`
    ]);

  return {
    id: workflow.id,
    name: workflow.name,
    active: Boolean(workflow.active),
    nodeCount: nodes.length,
    triggerNodes,
    likelyWebhookUrls
  };
}

async function testWebhook(testDef) {
  const start = Date.now();
  const method = testDef.method || 'POST';
  const path = String(testDef.path || testDef.webhookPath || '').replace(/^\/webhook\//, '').replace(/^\//, '');
  const url = `${WEBHOOK_BASE_URL}/webhook/${path}`;

  const headers = {
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  };

  if (WEBHOOK_HEADER_NAME && WEBHOOK_HEADER_VALUE) {
    headers[WEBHOOK_HEADER_NAME] = WEBHOOK_HEADER_VALUE;
  }

  const requestOptions = {
    method,
    url,
    headers,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };

  if (method !== 'GET') {
    requestOptions.body = testDef.body || {
      source: 'gda-qa-agent',
      mode: 'smoke',
      testRunId: body.testRunId || new Date().toISOString()
    };
  }

  const response = await httpRequest(requestOptions);
  const statusCode = responseStatus(response);
  const bodyPreview = responseBody(response);

  return {
    name: testDef.name || path,
    method,
    url,
    status: statusCode >= 200 && statusCode < 300 ? 'passed' : 'failed',
    httpStatus: statusCode,
    durationMs: Date.now() - start,
    responsePreview: bodyPreview
  };
}

async function testWebhookGroup(tests) {
  const results = [];

  for (const testDef of tests) {
    try {
      results.push(await testWebhook(testDef));
    } catch (error) {
      results.push({
        name: testDef.name || testDef.path,
        status: 'failed',
        error: error.message || String(error)
      });
    }
  }

  return {
    total: results.length,
    passed: results.filter((result) => result.status === 'passed').length,
    failed: results.filter((result) => result.status === 'failed').length,
    results
  };
}

async function latestFailedExecutions(limit = 25) {
  const result = await n8nApi(`/api/v1/executions?status=error&limit=${encodeURIComponent(limit)}`);

  if (!result.ok) {
    throw new Error(`n8n execution query failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
  }

  return result.body;
}

async function executionDetails(id) {
  if (!id) {
    throw new Error('execution_details requires executionId.');
  }

  const result = await n8nApi(`/api/v1/executions/${encodeURIComponent(id)}?includeData=true`);

  if (!result.ok) {
    throw new Error(`n8n execution detail failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
  }

  return result.body;
}

async function workflowDetails(id) {
  if (!id) {
    throw new Error('workflow_details requires workflowId.');
  }

  const result = await n8nApi(`/api/v1/workflows/${encodeURIComponent(id)}`);

  if (!result.ok) {
    throw new Error(`n8n workflow detail failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
  }

  return result.body;
}

async function main() {
  const action = body.action || 'health';

  if (action === 'health') {
    return {
      ok: true,
      agent: 'GDA.qa.agent-runner',
      mode: 'read-only',
      n8nBaseConfigured: Boolean(N8N_BASE_URL),
      n8nApiKeyConfigured: Boolean(N8N_API_KEY),
      webhookHeaderConfigured: Boolean(WEBHOOK_HEADER_NAME && WEBHOOK_HEADER_VALUE),
      supportedActions: [
        'health',
        'inventory_workflows',
        'test_selected_workflow_group',
        'test_react_used_workflows',
        'test_retool_used_workflows',
        'return_execution_failures',
        'return_latest_failed_workflows',
        'workflow_details'
      ]
    };
  }

  if (action === 'inventory_workflows') {
    const workflows = await fetchAllWorkflows();
    const inventory = workflows.map(workflowInventoryItem);

    return {
      ok: true,
      totalWorkflows: inventory.length,
      activeWorkflows: inventory.filter((workflow) => workflow.active).length,
      workflowsWithLikelyWebhookUrls: inventory.filter((workflow) => workflow.likelyWebhookUrls.length > 0).length,
      inventory
    };
  }

  if (action === 'test_selected_workflow_group') {
    return {
      ok: true,
      group: body.group || 'custom',
      ...(await testWebhookGroup(body.tests || []))
    };
  }

  if (action === 'test_react_used_workflows') {
    return {
      ok: true,
      group: 'react-used-workflows',
      ...(await testWebhookGroup(body.tests || reactUsedWebhookTests))
    };
  }

  if (action === 'test_retool_used_workflows') {
    return {
      ok: true,
      group: 'retool-used-workflows',
      ...(await testWebhookGroup(body.tests || retoolUsedWebhookTests))
    };
  }

  if (action === 'return_execution_failures' || action === 'return_latest_failed_workflows') {
    return {
      ok: true,
      executions: await latestFailedExecutions(body.limit || 25)
    };
  }

  if (action === 'workflow_details') {
    return {
      ok: true,
      workflow: await workflowDetails(body.workflowId)
    };
  }

if (action === 'execution_details') {
  return {
    ok: true,
    execution: await executionDetails(body.executionId)
  };
}

  return {
    ok: false,
    statusCode: 400,
    error: `Unsupported action: ${action}`
  };
}

try {
  const result = await main();
  return [{ json: result }];
} catch (error) {
  return [{ json: { ok: false, statusCode: 500, error: error.stack || error.message || String(error) } }];
}

